// Parse CSV response from ScraperCity store-leads download
// Handles both JSON array and CSV string responses

const raw = $input.first().json;

// If the API already returns parsed JSON array
if (Array.isArray(raw)) {
  return raw.map(item => ({ json: item }));
}

// If the response has a data property
if (raw.data && Array.isArray(raw.data)) {
  return raw.data.map(item => ({ json: item }));
}

// If it's a CSV string in the body
const csvText = typeof raw === 'string' ? raw : (raw.body || raw.csv || '');

if (!csvText) {
  return [{ json: { error: 'No parseable data returned', raw: JSON.stringify(raw).slice(0, 200) } }];
}

const lines = csvText.trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));

const results = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i];
  if (!line.trim()) continue;
  // Basic CSV split (handles quoted fields)
  const cols = [];
  let current = '';
  let inQuotes = false;
  for (const ch of line) {
    if (ch === '"') { inQuotes = !inQuotes; continue; }
    if (ch === ',' && !inQuotes) { cols.push(current.trim()); current = ''; continue; }
    current += ch;
  }
  cols.push(current.trim());
  const obj = {};
  headers.forEach((h, idx) => { obj[h] = cols[idx] || ''; });
  results.push({ json: obj });
}

return results;

// Aggregate all emails into a single array for bulk validation
const emails = $input.all().map(item => item.json.email).filter(Boolean);

// Store all original items so we can merge back after validation
const leads = $input.all().map(item => item.json);

return [{ json: { emails, leads } }];

// Merge original lead data with email validation results
// Validation results come back as array with email + status fields

const validationRaw = $input.first().json;

// Resolve validation results array
let validationResults = [];
if (Array.isArray(validationRaw)) {
  validationResults = validationRaw;
} else if (validationRaw.data && Array.isArray(validationRaw.data)) {
  validationResults = validationRaw.data;
} else if (validationRaw.results && Array.isArray(validationRaw.results)) {
  validationResults = validationRaw.results;
}

// Build lookup map: email -> validation result
const validationMap = {};
for (const v of validationResults) {
  const email = (v.email || v.address || '').toLowerCase().trim();
  if (email) {
    validationMap[email] = {
      emailStatus: v.status || v.email_status || v.result || 'unknown',
      isCatchAll: v.catch_all || v.is_catch_all || false,
      mxFound: v.mx_found || v.has_mx || false
    };
  }
}

// Retrieve original leads from the Collect Emails node
let leads = [];
try {
  const collectNode = $('Collect Emails for Validation').first();
  leads = collectNode.json.leads || [];
} catch(e) {
  // Fallback: leads array might be empty, continue gracefully
  leads = [];
}

if (!leads.length) {
  // If leads unavailable, just emit validation results directly
  return validationResults.map(v => ({ json: v }));
}

// Merge
const merged = leads.map(lead => {
  const email = (lead.email || '').toLowerCase().trim();
  const validation = validationMap[email] || { emailStatus: 'unknown', isCatchAll: false, mxFound: false };
  return {
    json: {
      ...lead,
      emailStatus: validation.emailStatus,
      isCatchAll: validation.isCatchAll,
      mxFound: validation.mxFound
    }
  };
});

return merged;

